import java.io.IOException;
import javax.servlet.http.HttpServlet;
import javax.servlet.http.HttpServletRequest;
import javax.servlet.http.HttpServletResponse;

public class SecureServlet extends HttpServlet {

    protected void doGet(HttpServletRequest request, HttpServletResponse response) throws IOException {
        String userInput = request.getParameter("input");
        String safeOutput = encodeForHTML(userInput);

        response.getWriter().println("<html><body>");
        response.getWriter().println("<h1>Hello, " + safeOutput + "!</h1>");
        response.getWriter().println("</body></html>");
    }

    private String encodeForHTML(String input) {
        return org.owasp.esapi.ESAPI.encoder().encodeForHTML(input);
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
